[SubscribesTo(classStr(PrintMgmtDocType), delegateStr(PrintMgmtDocType, getDefaultReportFormatDelegate))]

public static void PrintMgmtDocType_getDefaultReportFormatDelegate(PrintMgmtDocumentType _docType, EventHandlerResult _result)
{
       if(curExt() == "S004")
        {
            switch (_docType)
            {
                case PrintMgmtDocumentType::PurchaseOrderInvoice:
                    _result.result(ssrsReportStr(ETGVendInvoiceDocument, ETGPurchInvoice_S004));
                    break;

            }
        }


  else if(curExt() == "C003")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderInvoice:
                _result.result(ssrsReportStr(ETGVendInvoiceDocument, ETGPurchInvoice_C003));
                break;

        }
    }

    else if(curExt() == "O014")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderInvoice:
                _result.result(ssrsReportStr(ETGVendInvoiceDocument, ETGPurchInvoice_O014));
                break;

        }
    }
        else 
        {
            switch (_docType)
        {
        case PrintMgmtDocumentType::PurchaseOrderInvoice:
            _result.result(ssrsReportStr(ETGVendInvoiceDocument, ETGPurchInvoice));
            break;
        }
    }

}
